texttool_globals_dialog_message___confirmation_popup_message_remote_access_data = TextObject(bs_BA="Potvrdite aktiviranje daljinskog pristupa.", cs_CZ="Potvrďte aktivaci vzdáleného přístupu.", da_DK="Bekræft aktivering af fjernadgang.", de_DE="Bitte bestätige die Aktivierung des Fernzugriffs.", el_GR="Επιβεβαιώστε την ενεργοποίηση της απομακρυσμένης πρόσβασης.", en_GB="Please confirm activation of remote access.", es_ES="Confirme la activación del acceso remoto.", fi_FI="Vahvista etäkäytön aktivointi.", fr_FR="Veuillez confirmer l'activation de l'accès à distance.", hr_HR="Potvrdite aktiviranje daljinskog pristupa.", hu_HU="Erősítsd meg a távoli hozzáférés aktiválását.", it_IT="Confermare l'attivazione dell'accesso remoto.", nl_NL="Bevestig de activering van bediening op afstand.", no_NO="Bekreft aktivering av fjerntilgang.", pl_PL="Potwierdź aktywację dostępu zdalnego.", pt_PT="Por favor, confirma a ativação do acesso remoto.", ro_RO="Confirmaţi activarea accesului de la distanţă.", ru_RU="Подтвердите активацию удаленного доступа.", sk_SK="Prosím, potvrďte aktiváciu vzdialeného prístupu.", sl_SI="Potrdite aktivacijo oddaljenega dostopa.", sr_RS="Molimo da potvrdite aktiviranje daljinskog pristupa.", sv_SE="Bekräfta aktivering av fjärråtkomst.", tr_TR="Lütfen uzaktan erişimin etkinleştirilmesini onayla.", uk_UA="Будь ласка, підтвердіть активацію віддаленого доступу.")
